package br.com.samuel.stockly;import android.app.*;import android.content.*;import android.os.*;import android.text.*;import android.view.*;import android.widget.*;
public class LoginActivity extends Activity{EditText name,email,pass;Button primary,toggle;TextView title;boolean reg;AuthRepository repo;protected void onCreate(Bundle b){super.onCreate(b);Session s=new Session(this);if(s.logged()){startActivity(new Intent(this,DashboardActivity.class));finish();return;}repo=new AuthRepository(new DB(this),s);ScrollView sv=new ScrollView(this);LinearLayout r=Ui.root(this);sv.addView(r);title=Ui.tv(this,"Stockly Tutorial",26,true,Ui.TEXT);Ui.add(r,title);Ui.add(r,Ui.tv(this,"Primeiro cadastro vira ADMIN. Sem AndroidX/Material.",14,false,Ui.MUTED));LinearLayout c=Ui.card(this);name=Ui.input(this,"Nome completo");email=Ui.input(this,"E-mail");pass=Ui.input(this,"Senha");pass.setInputType(InputType.TYPE_CLASS_TEXT|InputType.TYPE_TEXT_VARIATION_PASSWORD);primary=Ui.btn(this,"Entrar",Ui.BLUE,0xffffffff);toggle=Ui.btn(this,"Criar nova conta",0xffffffff,Ui.BLUE);name.setVisibility(View.GONE);Ui.addM(c,name,4);Ui.addM(c,email,8);Ui.addM(c,pass,8);Ui.addM(c,primary,12);Ui.addM(c,toggle,8);Ui.addM(r,c,18);setContentView(sv);toggle.setOnClickListener(v->{reg=!reg;name.setVisibility(reg?View.VISIBLE:View.GONE);title.setText(reg?"Criar conta":"Stockly Tutorial");primary.setText(reg?"Cadastrar":"Entrar");toggle.setText(reg?"Já tenho conta":"Criar nova conta");});primary.setOnClickListener(v->submit());}void submit(){try{String n=name.getText().toString(),e=email.getText().toString(),p=pass.getText().toString();if(!e.contains("@")||!e.contains(".")){toast("E-mail inválido");return;}if(p.length()<4){toast("Senha mínima: 4 caracteres");return;}if(reg){if(n.trim().isEmpty()){toast("Informe seu nome");return;}repo.register(n,e,p);}else if(!repo.login(e,p)){toast("Credenciais inválidas");return;}startActivity(new Intent(this,DashboardActivity.class));finish();}catch(Exception ex){toast("Erro: "+ex.getMessage());}}void toast(String m){Toast.makeText(this,m,Toast.LENGTH_SHORT).show();}}
